import type GeoJSON from 'geojson';
import type { MapGeoJSONFeature, MapLayerMouseEvent } from 'maplibre-gl';

/**
 * Tries to deserialize an object, if serialized
 * @param serializedObject - string
 */
const deserializeObject = (
  serializedObject: string,
): string | Record<string, unknown> => {
  try {
    return JSON.parse(serializedObject);
  } catch {
    return serializedObject;
  }
};

/**
 * Deserializes map feature properties that are serialized
 *
 * @param featureProperties - map feature properties
 */
const parseFeatureProperties = (featureProperties: Record<string, unknown>) => {
  const properties: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(featureProperties)) {
    if (typeof value === 'string') {
      properties[key] = deserializeObject(value);
    } else {
      properties[key] = value;
    }
  }

  return properties;
};

/**
 * Extracts useful map features data for the tooltip
 * @param features - map features
 */
export const parseTooltipData = (features: MapGeoJSONFeature[]) => {
  const data: unknown[] = [];

  for (const feature of features) {
    const properties = parseFeatureProperties(feature.properties);
    const [latitude, longitude] = (feature.geometry as GeoJSON.Point)
      .coordinates;

    data.push({
      ...properties,
      latitude,
      longitude,
    });
  }

  return data;
};

export const extractDataFromEvent = (event: MapLayerMouseEvent) => {
  if (!event.features?.length) {
    return {};
  }
  const feature = event.features[0];
  const hoveredLayerId = feature.layer.id;
  const hoveredFeatures = event.features.filter(
    (feature) => feature.layer.id === hoveredLayerId,
  );

  const data = parseTooltipData(hoveredFeatures);

  return {
    featureId: `${hoveredLayerId}-${feature.id}`,
    hoveredLayerId,
    data,
  };
};
